sp_widget.client_script:
function ($scope, $rootScope,spAriaFocusManager, $http, amb,$timeout, spUtil, $location, $window, nowAttachmentHandler, $log, spAriaUtil, spModal, $uibModal, spNavStateManager) {
	/* widget controller */
	var c = this;

	$scope.btnCancelClick = function(){
		// close modal window
		$scope.$parent.buttonClicked($scope.$parent.options.buttons[0]);
	}

	$scope.btnStartButton = function(){
		$(".showAlert").hide().show('medium');
		c.data.currentStep = 'StartTemplate';
		c.server.update();
	}

	angular.element('.modal-footer').css({display:'none'});  

}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.10.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------


//------------------------------------------------------------------------------------------------------------------------
// CUSTOM
//------------------------------------------------------------------------------------------------------------------------


/* SECTIONS & FORMS */
//------------------------------------------------------------------------------------------------------------------------
.ng-isolate-scope .h4.ng-binding{
  font-weight: 400 !important;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif; //'Lucida Sans Unicode';
  padding-left: 5px;
	border-left-style: solid;
	border-left-color: $primary;
	border-left-width: 5px;
	color: $primary;
	padding-top: 8px;
	padding-bottom: 5px;
}

fieldset.ng-scope{
  margin-top: 5px;
}

label{
	//font-weight: 100!important;
  color: $primary;
}


/* DURATION */
//------------------------------------------------------------------------------------------------------------------------

#dur-minutes,
#dur-seconds { 
  visibility: hidden!important;
}

#dur-days,
#dur-hours { 
  width: 40px!important
}



/*
#sp_formfield_status[title^='Critical']::before{
  background-color: red!important;
}
*/


/* CLASSIFICATION */
//------------------------------------------------------------------------------------------------------------------------

.taskform-classification-banner {
  padding: 5px 10px 5px 10px; //before padding: 5px;
  border-radius: 5px;
  margin-bottom: 15px;
  margin-right: 5px; //new
	display: table-cell; border-radius: 8px; border: 3px solid white; //new

}



/*  ASSIGNMENT  */
//------------------------------------------------------------------------------------------------------------------------

//Assignment Group
.assignmentgroup-banner {
  background-color: $danger;
	color: $brand-danger-text;
  padding: 5px 10px 5px 10px;
  border-radius: 5px;
  margin-bottom: 15px;
  margin-right: 15px;
  display: table-cell; border-radius: 8px; border: 3px solid white; 
}


//------------------------------------------------------------------------------------------------------------------------




//------------------------------------------------------------------------------------------------------------------------
// OOTB FORM WIDGET
//------------------------------------------------------------------------------------------------------------------------


.btn-form-menu {
	vertical-align: inherit;
  padding: inherit;
  background: none;
}

.panel-title {
  word-wrap: break-word;
}

.panel-heading {
  .dropdown-menu {
    a {
      white-space: normal;
    }
  }
}

.sc-field-error-label {
  margin-right: .5em;
  display: inline-block;
  background-color: $sc-field-error-color;
}

.comment {
	font-weight: bold;
	margin-top: 2px;
	margin-bottom: 2px;
}
.mce-panel, .mce-btn {
	background-image: none;
	background-color: #f0f3f4;
}

.action-btn {
  margin-right: 5px;
}

.timeline-container {
   max-height: 50vh;
   height: 100%;
   overflow-y: auto;
}

.panel .panel {
    height: auto !important;
}

.attachment-button {
  .glyphicon-paperclip {
    font-size: 18px;
  }
}

.dropdown {
  .glyphicon-menu-hamburger:focus {
 		outline: thin dotted;
		outline: 5px auto $input-border-focus;
		outline-offset: -2px; 
	}
}

.empty-state-wrapper {
  width: 100%;
  height: 100%;
  align-items: center;
  display: flex;
  flex-direction: column;
  padding: 10vh 20px 20px;

  .empty-state {
    border: 1px solid #e7e9eb;
    border-radius: 10px;
    max-width: 700px;
    padding: 30px 40px 20px;
    position: relative;

    .empty-state-badge {
      top: -36px;
      left: 50%;
      position: absolute;
      height: 72px;
      width: 72px;
      -webkit-align-items: center;
      -ms-flex-align: center;
      align-items: center;
      border-radius: 100%;
      color: #ffffff;
      display: -webkit-flex;
      display: -ms-flexbox;
      display: flex;
      font-size: 40px;
      -webkit-justify-content: center;
      -ms-flex-pack: center;
      justify-content: center;
      margin-left: -36px;
      text-align: center;
    }

    .empty-state-header {
      font-size: 30px;
      text-align: center;
      color: #343d47;
    }

    .empty-state-content {
      ul {
        list-style: disc outside;
        margin: 0 0 10px 0;
        padding: 0 0 0 30px;
      }
    }
  }
}

.text-success-alt {
	background-color: $state-success-text;
}

.text-info-alt {
	background-color: $state-info-text;
}

sp_widget.script:
/**
 * Description
 * This widget opens when you click on "Run Process Template" 
 * @method anonymous-0
 * @author Karina Torres [KTorres]
 * @requires x_153465_discovert.module:sys_script_include.RunProcessTemplate
 * @memberof x_153465_discovert.module:sp_widget
 * @returns {undefined}
 */
(function($sp, input, data, options, gs) {
	/* populate the 'data' object */


	// rebuild the widget to run using template instance
	// RJ - TUP - STRY0068618
	data.process_template_sys_id = (input || {}).process_template_sys_id || (options || {}).process_template_sys_id;	
	var tTH = new TaskTemplateHelpers();
	if(input.currentStep == undefined){
		data.canAttach = false;
		// build the Template Instance Form here
		widgetParams = {
			table: "x_153465_discovert_discover_routing_runtime", 
			sys_id: "-1",	
			//view: "sp",
			disableUIActions: "true",
			//shared: {routing_template_ref: c.data.selected_Template_id},
			window_size : "10"
		};
		data.templateFormWidget = $sp.getWidget('widget-form', widgetParams);	
		data.templateFormWidget.data.f._fields = tTH.loadTemplateIntoInstanceForm(data.templateFormWidget.data.f._fields, data.process_template_sys_id);
		data.currentStep = 'enterInfo';
	} else if(input.currentStep == 'StartTemplate'){
		// take the data from the form and push into the standard input object for starting a template
		var templateInputs = {};
		templateInputs = tTH.loadTemplateInputsFromDataFields(input.templateFormWidget.data.f._fields);	
		tTH.startTemplateWithID(data.process_template_sys_id, true, templateInputs);
	}


})($sp, input, data, options, gs);
